To write unit tests for the `deep_get` function using `pytest`, we need to cover various scenarios including the happy path, edge cases, and error cases. Below are the tests that cover these scenarios:

```python
import pytest

def deep_get(d: dict, keys: str, default=None):
    """Get nested dict value by dot-separated keys."""
    for key in keys.split('.'):
        if isinstance(d, dict):
            d = d.get(key, default)
        else:
            return default
    return d

def test_deep_get_happy_path():
    """Test the happy path where the keys exist."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b.c') == 42

def test_deep_get_with_default():
    """Test when the keys do not exist and a default value is provided."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b.d', default='not found') == 'not found'

def test_deep_get_no_default():
    """Test when the keys do not exist and no default value is provided."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b.d') is None

def test_deep_get_empty_keys():
    """Test with an empty keys string."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, '') is None

def test_deep_get_non_dict_input():
    """Test when the input is not a dictionary."""
    data = ['a', 'b', 'c']
    assert deep_get(data, '0.1.2') is None

def test_deep_get_non_existent_key():
    """Test when a key in the path does not exist."""
    data = {
        'a': {
            'b': 10
        }
    }
    assert deep_get(data, 'a.b.c') is None

def test_deep_get_partial_path():
    """Test when a partial path is valid but the final key does not exist."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b') == {'c': 42}

def test_deep_get_nested_non_dict():
    """Test when a nested value is not a dictionary."""
    data = {
        'a': {
            'b': 10
        }
    }
    assert deep_get(data, 'a.b.c') is None

def test_deep_get_single_key():
    """Test with a single key."""
    data = {
        'a': 100
    }
    assert deep_get(data, 'a') == 100

def test_deep_get_root_key():
    """Test when the key is at the root level."""
    data = {
        'a': 100
    }
    assert deep_get(data, 'a') == 100
    assert deep_get(data, 'b', default='not found') == 'not found'

def test_deep_get_empty_dict():
    """Test with an empty dictionary."""
    data = {}
    assert deep_get(data, 'a.b.c') is None
    assert deep_get(data, 'a.b.c', default='not found') == 'not found'

def test_deep_get_none_input():
    """Test when the input dictionary is None."""
    assert deep_get(None, 'a.b.c') is None
    assert deep_get(None, 'a.b.c', default='not found') == 'not found'
```

These tests cover:

- The happy path where all keys exist.
- Cases where keys do not exist and a default value is provided.
- Cases where keys do not exist and no default value is provided.
- Edge cases like empty keys, non-dict inputs, and partial paths.
- Error cases like non-existent keys and nested non-dict values.
